function str_contains(str, substr)
    return str:find(substr, 1, true) ~= nil
end

local uri = ngx.var.uri -- get the request URI
if not (str_contains(uri, "/admin") or str_contains(uri, "/api")) then -- skip checks for admin and api endpoints
    local auth_header = ngx.req.get_headers()["Authorization"] -- get the Authorization header
    
